Fancybox.bind("[data-fancybox]", {
    // Your custom options
});

// animation 
const animationItems = document.querySelectorAll('.animation-item');
if (animationItems.length > 0) {
    function onEntry(e) {
        e.forEach(e => {
            e.isIntersecting && e.target.classList.add("animation-active")
        }
        )
    }
    let options = {
        threshold: [.5]
    }, observer = new IntersectionObserver(onEntry, options)
    for (let e of animationItems)
        observer.observe(e);
}
// end animation

/* hide header */
let scrollWidthFunc = () => {
    let scrollWidth = window.innerWidth - document.body.clientWidth;
    document.querySelector('html').style.paddingRight = scrollWidth + 'px';
    document.querySelector('header').style.paddingRight = scrollWidth + 'px';
}
const scrollTop = document.querySelector('.scroll-top');
if (scrollTop)
    scrollTop.addEventListener('click', () => {
        window.scrollTo({ top: 0, behavior: 'smooth' });
});


document.addEventListener("DOMContentLoaded", function () {
    /* burger menu */
    const header = document.querySelector("header");
    const burgerMenu = document.querySelector('.burger');
    
    let headerWasLight = false;
    
    if (burgerMenu) {
        const headerMobile = document.querySelector('.header__menu');
    
        burgerMenu.addEventListener("click", () => {
            const isOpening = !burgerMenu.classList.contains('active');
    
            if (isOpening) {
                headerWasLight = header.classList.contains("header--light");
                header.classList.remove("header--light");
    
                document.body.classList.add('burger-lock');
                document.documentElement.classList.add('burger-lock');
            } else {
                if (headerWasLight) {
                    header.classList.add("header--light");
                } else {
                    header.classList.remove("header--light");
                }
    
                document.body.classList.remove('burger-lock');
                document.documentElement.classList.remove('burger-lock');
            }
    
            headerMobile.classList.toggle("active");
            burgerMenu.classList.toggle("active");
            header.classList.toggle("active");
        });
    }
    /* end burger menu */


    /* Смена цвета шапки при скроле и над блоком header-transparent */
    const transparentSection = document.querySelector(".header-transparent");
    function changeColorHeader() {
        if (!transparentSection) {
            header.classList.add("header--light");
            return;
        }
    
        const headerHeight = header.offsetHeight;
        const sectionRect = transparentSection.getBoundingClientRect();
    
        const isOverTransparent =
            sectionRect.top <= 0 &&
            sectionRect.bottom > headerHeight;
    
        const shouldBeLight = window.scrollY > 100 || !isOverTransparent;
        header.classList.toggle("header--light", shouldBeLight);
    }
    
    changeColorHeader();
    window.addEventListener("scroll", changeColorHeader);
    /* end смена цвета шапки */



    /* mobile menu */
    const headerNav = document.getElementsByClassName('header__nav-item')
	for (let i = 0; i < headerNav.length; i++) {
        if(headerNav[i]) {
            headerNav[i].addEventListener('click', function () {
                const headerSublist = this.querySelector('.header__nav-sublist'); 
                if (headerSublist.classList.contains('active')) {
                    headerSublist.classList.remove('active');
                    this.classList.remove('active');
                    headerSublist.style.maxHeight = '0'; 
                } else {
                    headerSublist.classList.add('active');
                    this.classList.add('active');
    
                    const contentHeight = headerSublist.scrollHeight;
                    headerSublist.style.maxHeight = `${contentHeight}px`;
                }
            })
        }
	}
    /* end mobile menu */



    // Popups
    function popupClose(popupActive) {
        popupActive.classList.remove('open');
        setTimeout(() => {
            if (!popupActive.classList.contains('open')) {
                popupActive.classList.remove('active');
            }
        }, 400);
        document.body.classList.remove('lock');
        document.querySelector('html').style.paddingRight = 0;
        document.querySelector('html').classList.remove('lock');
        document.querySelector('header').removeAttribute('style');


    }
    const popupOpenBtns = document.querySelectorAll('.popup-btn');
    const popups = document.querySelectorAll('.popup');
    const originalTitlePopup2 = document.querySelector('.original-title').innerHTML;
    const closePopupBtns = document.querySelectorAll('.close-popup-btn');
    closePopupBtns.forEach(function (el) {
        el.addEventListener('click', function (e) {
            popupClose(e.target.closest('.popup'));
        });
    });
    popupOpenBtns.forEach(function (el) {
        el.addEventListener('click', function (e) {
            e.preventDefault();
            const path = e.currentTarget.dataset.path;
            const currentPopup = document.querySelector(`[data-target="${path}"]`);
            if (currentPopup) {
                popups.forEach(function (popup) {
                    popupClose(popup);
                    popup.addEventListener('click', function (e) {
                        if (!e.target.closest('.popup__content')) {
                            popupClose(e.target.closest('.popup'));
                        }
                    });
                });
                currentPopup.classList.add('active');
                setTimeout(() => {
                    currentPopup.classList.add('open');
                }, 10);
                if (currentPopup.getAttribute('data-target') == 'popup-change') {

                    let originaTitle = currentPopup.querySelector('.original-title');
                    if (el.classList.contains('change-item__btn')) {
                        if (el.classList.contains('change-item__btn_current')) {
                            originaTitle.textContent = el.textContent;
                        }
                        else {
                            let currentItem = el.closest('.change-item');
                            let currentTitile = currentItem.querySelector('.change-item__title');
                            originaTitle.innerHTML = currentTitile.innerHTML
                        }
                    }
                    else {
                        originaTitle.innerHTML = originalTitlePopup2;
                    }
                }
                e.stopPropagation();
                scrollWidthFunc();
                document.querySelector('html').classList.add('lock');
            }
        });
    });
    // end popups


    // раскрытие картинок в блоке Примеры работ
    document.querySelectorAll('.examples__card-img')?.forEach(item => {
        item.addEventListener('click', function (e) {
            e.preventDefault();
    
            const block = this.closest('.examples__card-pictures');
            if (!block) return;
    
            const bigImg = block.querySelector('.examples__card-pic img');
            const bigSource = block.querySelector('.examples__card-pic source');
    
            const smallImg = this.querySelector('img');
            const smallSource = this.querySelector('source');
    
            if (bigImg && smallImg) {
                bigImg.src = smallImg.src;
            }
    
            if (bigSource && smallSource) {
                bigSource.srcset = smallSource.srcset;
            }
        });
    });
    // end раскрытие картинок 


    /* calculator */
    const calculatorPages = document.querySelectorAll('.calculator__form-page');
    const calculatorNextBtns = document.querySelectorAll('.calculator__form-btn-next');
    
    if(calculatorPages.length  && calculatorNextBtns.length ) {
        let currentPage = 0;
        calculatorPages[currentPage].classList.add('active');
    
        function showPage(index) {
            calculatorPages.forEach(page => page.classList.remove('active'));
            calculatorPages[index].classList.add('active');
        }
    
        calculatorNextBtns.forEach(btn => {
            btn.addEventListener('click', (e) => {
                e.preventDefault();
        
                const currentInputs = calculatorPages[currentPage].querySelectorAll('input[type="radio"]');
                if (currentInputs.length) {
                    const isChecked = [...currentInputs].some(input => input.checked);
                    if (!isChecked) {
                        alert('Выберите вариант');
                        return;
                    }
                }
                currentPage++;
        
                if (currentPage < calculatorPages.length) {
                    showPage(currentPage);
                    updatePagination();
                }
            });
        });

        const totalPages = calculatorPages.length;

        function updatePagination() {
            const current = calculatorPages[currentPage].querySelector('.current');
            const total = calculatorPages[currentPage].querySelector('.total');

            if (current && total) {
                current.textContent = String(currentPage + 1).padStart(2, '0');
                total.textContent = String(totalPages).padStart(2, '0');
            }
        }

        updatePagination();
    }
    /* end calculator */


    /*  accordion  */
    const accordions = document.querySelectorAll('.accordion');

    accordions?.forEach(accordion => {
        accordion.addEventListener('click', () => {
            const content = accordion.querySelector('.accordion__content') || accordion.parentElement.querySelector('.accordion__content');
            const isActive = accordion.classList.contains('active');
    
            accordions.forEach(item => {
                const itemContent = item.querySelector('.accordion__content') || item.parentElement.querySelector('.accordion__content');
    
                item.classList.remove('active');
    
                if (itemContent) {
                    itemContent.classList.remove('active');
                    itemContent.style.maxHeight = '0';
                }
            });
    
            if (!isActive) {
                accordion.classList.add('active');
                content.classList.add('active');
                content.style.maxHeight = content.scrollHeight + 'px';
            }
        });
    });

    const faqItems = document.querySelectorAll('.faq__item');
    if (faqItems.length > 0) {
        faqItems[0].click();
    }
	/*  end accordion   */


    /* фильтрация карточек */
    document.querySelectorAll('.filter').forEach(filterBlock => {
        const filterButtons = filterBlock.querySelectorAll('.filter-btn');
        const filterCards = filterBlock.querySelectorAll('.filter-card');
      
        filterButtons.forEach(button => {
          button.addEventListener('click', () => {
            const filterId = button.dataset.id;
      
            filterCards.forEach(card => {
              const isMatch =
                filterId === 'all' || card.dataset.id === filterId;
      
              if (isMatch) {
                card.classList.remove('hidden');
              } else {
                card.classList.add('hidden');
              }
            });
      
            // активная кнопка только в рамках этого filter-блока
            filterButtons.forEach(btn => btn.classList.remove('active'));
            button.classList.add('active');
          });
        });
      });
    /* end фильтрация карточек */


    /*  btn more  */
    const moreBtns = document.querySelectorAll('.btn-more');
    moreBtns.forEach(moreBtn => {
        if (moreBtn) {
            const moreContent = moreBtn.previousElementSibling;

            if (moreContent.scrollHeight <= moreContent.clientHeight) {
                moreBtn.style.display = 'none'; 
            } else {
                const textBtn = moreBtn.innerHTML; 
                moreBtn.addEventListener('click', function() {
                    const heightMoreContent = moreContent.style.maxHeight; 
                    this.classList.toggle('active');

                    if (moreContent.style.maxHeight) {
                        moreContent.style.maxHeight = null;
                        this.textContent = textBtn;
                    } else {
                        moreContent.style.maxHeight = moreContent.scrollHeight + "px"; 
                        this.textContent = 'Свернуть';
                    }
                });
            }
        }
    });
    /*  end btn more  */


    /* navigation */
    const articleNavigation = document.querySelector(".navigation");
    if (articleNavigation) {
        const headings = document.querySelectorAll(
            ".text-block h1, .text-block h2, .text-block h3, .text-block h4"
        );

        const articleNavigationList = document.querySelector(".navigation__list");

        if (headings.length > 0 && articleNavigationList) {
            headings.forEach((heading, i) => {
                const titleBlock = heading.textContent.trim();
                const id = `section-${i}`;

                heading.setAttribute("id", id);

                const articleNavigationItem = document.createElement("li");
                const articleNavigationLink = document.createElement("a");
                const articleNavigationSpan = document.createElement("span");

                articleNavigationLink.classList.add("navigation__link");
                articleNavigationLink.setAttribute("href", `#${id}`);
                articleNavigationSpan.textContent = " " + titleBlock;

                articleNavigationLink.append(articleNavigationSpan);
                articleNavigationItem.append(articleNavigationLink);
                articleNavigationList.append(articleNavigationItem);
            });

            const navLinks = document.querySelectorAll('.navigation__link');

            navLinks.forEach((link) => {
                link.addEventListener("click", function (e) {
                    e.preventDefault();

                    const href = this.getAttribute("href").substring(1);
                    const scrollTarget = document.getElementById(href);

                    if (!scrollTarget) return;

                    const topOffset = 170;
                    const elementPosition = scrollTarget.getBoundingClientRect().top;
                    const offsetPosition = elementPosition + window.pageYOffset - topOffset;

                    window.scrollTo({
                        top: offsetPosition,
                        behavior: "smooth",
                    });
                });
            });

            const observer = new IntersectionObserver(
                (entries) => {
                    entries.forEach((entry) => {
                        if (entry.isIntersecting) {
                            const currentId = entry.target.id;

                            navLinks.forEach((link) => {
                                link.classList.remove("active");

                                if (link.getAttribute("href") === `#${currentId}`) {
                                    link.classList.add("active");
                                }
                            });
                        }
                    });
                },
                {
                    root: null,
                    rootMargin: "-30% 0px -55% 0px",
                    threshold: 0,
                }
            );

            headings.forEach((heading) => observer.observe(heading));
        } else {
            const innerNavigation = articleNavigation.querySelector(".navigation");
            if (innerNavigation) {
                innerNavigation.remove();
            }
        }
    }
    /* end navigation */

    /* Плавный скрол */
    document.querySelectorAll('.scroll-link').forEach(link => {
        link.addEventListener('click', function (e) {
            e.preventDefault();
    
            const targetId = this.getAttribute('href');
            const target = document.querySelector(targetId);
    
            if (!target) return;
    
            const offset = 170;
            const targetPosition =
                target.getBoundingClientRect().top + window.pageYOffset - offset;
    
            window.scrollTo({
                top: targetPosition,
                behavior: 'smooth'
            });
        });
    });
})


/* Раскрытие карточек Примеры работ */
document.addEventListener("DOMContentLoaded", () => {
    const cards = document.querySelectorAll(".examples__card-js");
    let openedCard = null;

    const getClosedHeight = (card) => {
        const main = card.querySelector(".examples__card-main");
        const top = card.querySelector(".examples__card-top-js");

        if (!main || !top) return 0;

        const styles = window.getComputedStyle(main);
        const paddingTop = parseFloat(styles.paddingTop) || 0;
        const paddingBottom = parseFloat(styles.paddingBottom) || 0;

        return Math.ceil(top.getBoundingClientRect().height + paddingTop + paddingBottom);
    };

    const getOpenHeight = (card) => {
        const prevHeight = card.style.height;
        const wasOpen = card.classList.contains("is-open");

        card.classList.add("is-open");
        card.style.height = "auto";

        const height = Math.ceil(card.scrollHeight);

        card.style.height = prevHeight;

        if (!wasOpen) {
            card.classList.remove("is-open");
        }

        return height;
    };

    const updateCardHeight = (card) => {
        if (!card) return;

        card.style.height = card.classList.contains("is-open")
            ? `${getOpenHeight(card)}px`
            : `${getClosedHeight(card)}px`;
    };

    const closeCard = (card) => {
        if (!card) return;

        const currentHeight = Math.ceil(card.getBoundingClientRect().height);
        const closedHeight = getClosedHeight(card);

        card.style.height = `${currentHeight}px`;

        requestAnimationFrame(() => {
            card.classList.remove("is-open");
            card.style.height = `${closedHeight}px`;
        });

        if (openedCard === card) {
            openedCard = null;
        }
    };

    const openCard = (card) => {
        if (!card || card.classList.contains("is-open")) return;

        if (openedCard && openedCard !== card) {
            closeCard(openedCard);
        }

        const currentHeight = Math.ceil(card.getBoundingClientRect().height);

        card.style.height = `${currentHeight}px`;
        card.classList.add("is-open");

        requestAnimationFrame(() => {
            card.style.height = `${getOpenHeight(card)}px`;
        });

        openedCard = card;
    };

    cards.forEach((card) => {
        const top = card.querySelector(".examples__card-top-js");

        updateCardHeight(card);

        card.addEventListener("click", (e) => {
            if (top && top.contains(e.target) && card.classList.contains("is-open")) return;
            if (card.classList.contains("is-open")) return;

            if (openedCard && openedCard !== card) {
                closeCard(openedCard);
            }

            openCard(card);
        });

        if (top) {
            top.addEventListener("click", (e) => {
                if (!card.classList.contains("is-open")) return;

                e.stopPropagation();
                closeCard(card);
            });
        }

        card.addEventListener("transitionend", (e) => {
            if (e.propertyName !== "height") return;
            updateCardHeight(card);
        });

        card.querySelectorAll("img").forEach((img) => {
            if (!img.complete) {
                img.addEventListener("load", () => updateCardHeight(card));
            }
        });

        if ("ResizeObserver" in window) {
            const observer = new ResizeObserver(() => {
                updateCardHeight(card);
            });

            const main = card.querySelector(".examples__card-main");
            const pictures = card.querySelector(".examples__card-pictures");

            if (main) observer.observe(main);
            if (pictures) observer.observe(pictures);
        }
    });

    window.addEventListener("resize", () => {
        cards.forEach(updateCardHeight);
    });
});


